func gitStageBlob(ctx context.Context, repoRoot string, stage int, path string) ([]byte, error) {
	spec := fmt.Sprintf(":%d:%s", stage, path)
	out, err := gitpkg.Command(ctx, repoRoot, "show", spec).Output()
	if err != nil {
